trigger AccountTrigger on Account (before delete) {
    if (Trigger.isBefore && Trigger.isDelete) {
        AccountTriggerHandler.handleBeforeDelete(Trigger.old);
    }
}

public class AccountTriggerHandler {
    /**
     * Handles the before delete operations for Account records.
     * Checks for open Opportunities and prevents deletion if found.
     *
     * @param oldAccounts List of Account records to be deleted.
     */
    public static void handleBeforeDelete(List<Account> oldAccounts) {
        Set<Id> accountIds = new Set<Id>();
        for (Account acc : oldAccounts) {
            accountIds.add(acc.Id);
        }

        // Query once outside the loop
        List<Opportunity> openOpps = [
            SELECT AccountId FROM Opportunity
            WHERE AccountId IN :accountIds AND StageName NOT IN ('Closed Won', 'Closed Lost')
            WITH SECURITY_ENFORCED
        ];

        // Map to store account Ids with open opportunities
        Set<Id> accountsWithOpenOpps = new Set<Id>();
        for (Opportunity opp : openOpps) {
            accountsWithOpenOpps.add(opp.AccountId);
        }

        // Check each account and add an error if it has open opportunities
        for (Account acc : oldAccounts) {
            if (accountsWithOpenOpps.contains(acc.Id)) {
                acc.addError('Cannot delete account with open opportunities.');
            }
        }
    }
}

@isTest
private class AccountTriggerHandlerTest {
    @TestSetup
    static void setupTestData() {
        List<Account> accounts = new List<Account>();
        for (Integer i = 0; i < 200; i++) {
            accounts.add(new Account(Name = 'Test Account ' + i));
        }
        insert accounts;

        List<Opportunity> opportunities = new List<Opportunity>();
        for (Account acc : accounts) {
            opportunities.add(new Opportunity(Name = 'Opportunity ' + acc.Name,
                                              StageName = 'Prospecting',
                                              CloseDate = Date.today().addDays(30),
                                              AccountId = acc.Id));
        }
        insert opportunities;
    }

    @isTest
    static void testBulkAccountDeletion() {
        List<Account> accounts = [SELECT Id FROM Account];

        Test.startTest();
        try {
            delete accounts;
            System.assert(false, 'Expected DMLException not thrown.');
        } catch (DmlException e) {
            System.assert(e.getMessage().contains('Cannot delete account with open opportunities'),
                           'Unexpected error message: ' + e.getMessage());
        }
        Test.stopTest();
    }

    @isTest
    static void testSingleAccountDeletion() {
        Account account = [SELECT Id FROM Account LIMIT 1];

        Test.startTest();
        try {
            delete account;
            System.assert(false, 'Expected DMLException not thrown.');
        } catch (DmlException e) {
            System.assert(e.getMessage().contains('Cannot delete account with open opportunities'),
                           'Unexpected error message: ' + e.getMessage());
        }
        Test.stopTest();
    }

    @isTest
    static void testDeletionWithoutOpenOpportunities() {
        Account account = new Account(Name = 'No Opportunity Account');
        insert account;

        Test.startTest();
        delete account; // This should succeed as no opportunities are related
        Test.stopTest();

        // Verify the account is indeed deleted
        Account deletedAcc = [SELECT Id FROM Account WHERE Id = :account.Id ALL ROWS];
        System.assert(deletedAcc != null && deletedAcc.IsDeleted,
                      'The account should be deleted.');
    }
}

trigger AccountPreventDeleteTrigger on Account (before delete) {
    if(Trigger.isBefore && Trigger.isDelete) {
        AccountPreventDeleteTriggerHandler.handleBeforeDelete(Trigger.old);
    }
}

/**
 * Handler class for AccountPreventDeleteTrigger
 */
public class AccountPreventDeleteTriggerHandler {
    /**
     * Handles the before delete logic for account records.
     *
     * @param oldAccounts List of account records that are being deleted.
     * @throws PreventAccountDeletionException if account has open opportunities.
     */
    public static void handleBeforeDelete(List<Account> oldAccounts) {
        // Collect all account IDs
        Set<Id> accountIds = new Set<Id>();
        for(Account acc : oldAccounts) {
            accountIds.add(acc.Id);
        }

        try {
            // Query for any open opportunities related to these accounts
            Map<Id, Integer> accountToOpenOppCount = new Map<Id, Integer>();
            for(AggregateResult result : [
                SELECT AccountId, COUNT(Id) cnt
                FROM Opportunity
                WHERE AccountId IN :accountIds AND IsClosed = false
                GROUP BY AccountId
            ]) {
                accountToOpenOppCount.put((Id)result.get('AccountId'), (Integer)result.get('cnt'));
            }

            // Check for open opportunities and gather exceptions
            List<String> errors = new List<String>();
            for(Account acc : oldAccounts) {
                Integer openOppCount = accountToOpenOppCount.get(acc.Id);
                if(openOppCount != null && openOppCount > 0) {
                    errors.add('Cannot delete account with open opportunities: ' + acc.Id);
                }
            }

            // Throw exception if any errors collected
            if (!errors.isEmpty()) {
                throw new PreventAccountDeletionException(String.join(errors, '; '));
            }
        } catch (DmlException e) {
            // Handle unexpected DML errors
            throw new PreventAccountDeletionException('Unexpected error occurred: ' + e.getMessage());
        }
    }

    /**
     * Custom exception for account deletion prevention
     */
    public class PreventAccountDeletionException extends Exception {}
}

@isTest
/**
 * Test class for AccountPreventDeleteTriggerHandler
 */
private class AccountPreventDeleteTriggerTest {
    @TestSetup
    static void setUpTestData() {
        // Create an account
        Account testAccount = new Account(Name = 'Test Account');
        insert testAccount;

        // Create closed opportunity
        Opportunity closedOpp = new Opportunity(Name = 'Closed Opp', AccountId = testAccount.Id, StageName = 'Closed Won', CloseDate = Date.today(), IsClosed = true);
        insert closedOpp;

        // Create open opportunity
        Opportunity openOpp = new Opportunity(Name = 'Open Opp', AccountId = testAccount.Id, StageName = 'Prospecting', CloseDate = Date.today().addDays(30), IsClosed = false);
        insert openOpp;
    }

    @isTest
    static void testPreventAccountDeletionWithOpenOpportunities() {
        // Retrieve account
        Account testAccount = [SELECT Id FROM Account WHERE Name = 'Test Account' LIMIT 1];

        try {
            delete testAccount;
            System.assert(false, 'Expected PreventAccountDeletionException was not thrown');
        } catch (AccountPreventDeleteTriggerHandler.PreventAccountDeletionException e) {
            System.assert(e.getMessage().contains('Cannot delete account with open opportunities'), 'Exception message does not match expected.');
        }
    }

    @isTest
    static void testAllowAccountDeletionWithNoOpenOpportunities() {
        // Create an account with no opportunities
        Account accountWithoutOpps = new Account(Name = 'No Opps Account');
        insert accountWithoutOpps;

        Test.startTest();
        delete accountWithoutOpps;
        Test.stopTest();
    }

    @isTest
    static void testBulkAccountDeletion() {
        // Create multiple accounts with closed opportunities
        List<Account> accounts = new List<Account>();
        for(Integer i = 0; i < 200; i++) {
            Account testAccount = new Account(Name = 'Bulk Account ' + i);
            accounts.add(testAccount);
        }
        insert accounts;

        Test.startTest();
        delete accounts;
        Test.stopTest();
    }
}
